WITH f AS (SELECT m.*, AVG(cash_inflow_observed) OVER(PARTITION BY business_id ORDER BY month ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) cash_inflow_3m_avg, cash_inflow_observed - LAG(cash_inflow_observed) OVER(PARTITION BY business_id ORDER BY month) cash_inflow_mom_change, AVG(net_cash_flow_observed) OVER(PARTITION BY business_id ORDER BY month ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) net_cash_flow_3m_avg, STDDEV(net_cash_flow_observed) OVER(PARTITION BY business_id ORDER BY month ROWS BETWEEN 5 PRECEDING AND CURRENT ROW) net_cash_flow_6m_volatility, AVG(scheduled_debt_service / NULLIF(cash_inflow_observed,0)) OVER(PARTITION BY business_id ORDER BY month ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) repayment_burden_3m_avg, AVG(payroll_amount / NULLIF(cash_inflow_observed,0)) OVER(PARTITION BY business_id ORDER BY month ROWS BETWEEN 2 PRECEDING AND CURRENT ROW) payroll_burden_3m_avg FROM business_monthly_snapshots m) SELECT f.*, o.future_60d_cash_stress_observed AS label_future_60d_cash_stress FROM f LEFT JOIN business_monthly_outcomes o USING(business_id, month) WHERE o.future_60d_cash_stress_observed IS NOT NULL;